import { describe, it, expect } from 'bun:test';
import {
  PhysicalQuasicrystallineClock,
  encodeIndex,
  witnessAt,
  circularDistance,
  trajectoryDrift,
  LATTICE_SCALE_NS,
  PHYSICAL_CLOCK_INDEX_CAP,
  type PhysicalClockReading,
} from './quasicrystalline-physical-clock';
import { evaluatePhase, PulsePhase } from './quasicrystalline-clock';

describe('Physical Quasicrystalline Clock', () => {
  it('now() returns a structurally valid reading', () => {
    const clock = new PhysicalQuasicrystallineClock();
    const reading = clock.now();
    expect(typeof reading.timestamp).toBe('bigint');
    expect(reading.pisotIndex).toBeGreaterThanOrEqual(0);
    expect(reading.pisotIndex).toBeLessThan(PHYSICAL_CLOCK_INDEX_CAP);
    expect(evaluatePhase(reading.cassiniWitness)).not.toBe(PulsePhase.Invalid);
  });

  it('a fresh now() passes validate() against the same clock', () => {
    const clock = new PhysicalQuasicrystallineClock();
    const reading = clock.now();
    const result = clock.validate(reading);
    expect(result.valid).toBe(true);
    expect(result.source).toBeNull();
  });

  it('Cassini witness corruption fails validate()', () => {
    const clock = new PhysicalQuasicrystallineClock();
    const reading = clock.now();
    const corrupted: PhysicalClockReading = {
      ...reading,
      cassiniWitness: {
        prev: reading.cassiniWitness.prev,
        curr: reading.cassiniWitness.curr + 7n, // break the Fibonacci identity
        next: reading.cassiniWitness.next,
      },
    };
    const result = clock.validate(corrupted);
    expect(result.valid).toBe(false);
    expect(result.source).toBe('cassini');
  });

  it('two clocks running concurrently agree within drift bound', () => {
    const a = new PhysicalQuasicrystallineClock();
    const b = new PhysicalQuasicrystallineClock();
    for (let i = 0; i < 50; i++) {
      const ra = a.now();
      const rb = b.now();
      const driftA = a.validate(rb);
      const driftB = b.validate(ra);
      expect(driftA.valid).toBe(true);
      expect(driftB.valid).toBe(true);
      expect(driftA.drift).toBeLessThanOrEqual(1);
      expect(driftB.drift).toBeLessThanOrEqual(1);
    }
  });

  it('drift bound violation: a far-out-of-sync clock is rejected', () => {
    let t = 0n;
    const fast = new PhysicalQuasicrystallineClock({
      maxDrift: 2,
      timeSource: () => t,
    });
    const slow = new PhysicalQuasicrystallineClock({
      maxDrift: 2,
      timeSource: () => t,
    });
    // advance the fast clock by 20 lattice units worth of ns
    t += 20n * LATTICE_SCALE_NS;
    const slowReading = slow.now(); // slow takes its reading at t=20*scale
    // reset t back so the fast clock thinks it is much earlier
    t = 0n;
    // re-create slow with the original epoch via direct reading injection:
    const remote: PhysicalClockReading = {
      timestamp: 0n,
      pisotIndex: 25 % PHYSICAL_CLOCK_INDEX_CAP,
      cassiniWitness: witnessAt(25 % PHYSICAL_CLOCK_INDEX_CAP),
    };
    const result = fast.validate(remote);
    // fast clock is at index 0, remote at 25; drift exceeds maxDrift=2.
    expect(result.valid).toBe(false);
    expect(result.source).toBe('drift');
    expect(result.drift).toBeGreaterThan(2);
    void slowReading;
  });

  it('drift trajectory: 100 rapid readings obey Lipschitz bound (≤ 100)', () => {
    const clock = new PhysicalQuasicrystallineClock();
    for (let i = 0; i < 100; i++) clock.now();
    const traj = clock.getTrajectory(100);
    expect(traj.length).toBe(100);
    const total = trajectoryDrift(traj);
    // Per-round shift is ≤ 1 lattice unit; cumulative drift over 100 rounds ≤ 100.
    expect(total).toBeLessThanOrEqual(100);
  });

  it('encodeIndex buckets ns into lattice units', () => {
    expect(encodeIndex(0n)).toBe(0);
    expect(encodeIndex(LATTICE_SCALE_NS - 1n)).toBe(0);
    expect(encodeIndex(LATTICE_SCALE_NS)).toBe(1);
    expect(encodeIndex(3n * LATTICE_SCALE_NS)).toBe(3);
  });

  it('circularDistance is symmetric and bounded by cap/2', () => {
    expect(circularDistance(0, 0)).toBe(0);
    expect(circularDistance(1, 5)).toBe(4);
    expect(circularDistance(5, 1)).toBe(4);
    expect(circularDistance(0, PHYSICAL_CLOCK_INDEX_CAP - 1)).toBe(1);
  });
});
